package com.example.sociallogin

import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.util.Log
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.IntentSenderRequest
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import com.facebook.AccessToken
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.FacebookSdk
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.identity.BeginSignInRequest
import com.google.android.gms.auth.api.identity.Identity
import com.google.android.gms.auth.api.identity.SignInClient

data class SocialLoginResult(
    val provider: String,
    val token: String,
    val userId: String?,
    val email: String?,
    val displayName: String?
)

interface SocialLoginCallback {
    fun onLoginSuccess(result: SocialLoginResult)
    fun onLoginFailure(provider: String, error: String)
    fun onLoginCancelled(provider: String)
}

class SocialLoginManager(private val activity: AppCompatActivity) {

    companion object {
        private const val TAG = "SocialLoginManager"

        // Loaded from BuildConfig / secure storage — NOT hardcoded
        // The app-level build.gradle reads these from local.properties
        // Secrets (Facebook App Secret, Google Client Secret) stay on your backend server
    }

    private var callback: SocialLoginCallback? = null

    // --- Facebook ---
    private val callbackManager: CallbackManager = CallbackManager.Factory.create()
    private val facebookLoginManager: LoginManager = LoginManager.getInstance()

    // --- Google One Tap ---
    private lateinit var oneTapClient: SignInClient
    private lateinit var signInRequest: BeginSignInRequest
    private lateinit var googleSignInLauncher: ActivityResultLauncher<IntentSenderRequest>

    fun initialize(loginCallback: SocialLoginCallback) {
        this.callback = loginCallback
        initializeFacebook()
        initializeGoogle()
    }

    // ==================== FACEBOOK ====================

    private fun initializeFacebook() {
        // Facebook App ID is set via AndroidManifest.xml meta-data,
        // which reads from manifestPlaceholders in build.gradle
        facebookLoginManager.registerCallback(callbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    val accessToken = result.accessToken
                    Log.d(TAG, "Facebook login success")
                    // Send this token to YOUR BACKEND SERVER for verification
                    // Your server uses the App Secret (stored securely on server) to validate
                    callback?.onLoginSuccess(
                        SocialLoginResult(
                            provider = "facebook",
                            token = accessToken.token,
                            userId = accessToken.userId,
                            email = null, // Fetch via Graph API on your backend
                            displayName = null
                        )
                    )
                }

                override fun onCancel() {
                    Log.d(TAG, "Facebook login cancelled")
                    callback?.onLoginCancelled("facebook")
                }

                override fun onError(error: FacebookException) {
                    Log.e(TAG, "Facebook login error", error)
                    callback?.onLoginFailure("facebook", error.message ?: "Unknown error")
                }
            })
    }

    fun loginWithFacebook() {
        facebookLoginManager.logInWithReadPermissions(
            activity,
            callbackManager,
            listOf("email", "public_profile")
        )
    }

    fun handleFacebookActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
    }

    // ==================== GOOGLE ====================

    private fun initializeGoogle() {
        oneTapClient = Identity.getSignInClient(activity)

        // Google Client ID (public identifier, safe for client-side use)
        // Google Client SECRET must only be on your server
        val googleClientId = BuildConfig.GOOGLE_CLIENT_ID

        signInRequest = BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    .setServerClientId(googleClientId)
                    .setFilterByAuthorizedAccounts(false)
                    .build()
            )
            .setAutoSelectEnabled(true)
            .build()

        googleSignInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result ->
            handleGoogleSignInResult(result.resultCode, result.data)
        }
    }

    fun loginWithGoogle() {
        oneTapClient.beginSignIn(signInRequest)
            .addOnSuccessListener(activity) { beginSignInResult ->
                try {
                    val intentSenderRequest = IntentSenderRequest.Builder(
                        beginSignInResult.pendingIntent.intentSender
                    ).build()
                    googleSignInLauncher.launch(intentSenderRequest)
                } catch (e: Exception) {
                    Log.e(TAG, "Google sign-in launch failed", e)
                    callback?.onLoginFailure("google", e.message ?: "Launch failed")
                }
            }
            .addOnFailureListener(activity) { e ->
                Log.e(TAG, "Google sign-in begin failed", e)
                callback?.onLoginFailure("google", e.message ?: "No Google accounts found")
            }
    }

    private fun handleGoogleSignInResult(resultCode: Int, data: Intent?) {
        try {
            val credential = oneTapClient.getSignInCredentialFromIntent(data)
            val idToken = credential.googleIdToken

            if (idToken != null) {
                Log.d(TAG, "Google login success")
                // Send this ID token to YOUR BACKEND SERVER for verification
                // Your server uses the Client Secret (stored securely on server) to validate
                callback?.onLoginSuccess(
                    SocialLoginResult(
                        provider = "google",
                        token = idToken,
                        userId = credential.id,
                        email = credential.id,
                        displayName = credential.displayName
                    )
                )
            } else {
                callback?.onLoginFailure("google", "No ID token received")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Google sign-in result handling failed", e)
            callback?.onLoginFailure("google", e.message ?: "Unknown error")
        }
    }

    // ==================== LOGOUT ====================

    fun logout() {
        // Facebook logout
        if (AccessToken.getCurrentAccessToken() != null) {
            facebookLoginManager.logOut()
        }

        // Google sign out
        oneTapClient.signOut()
            .addOnCompleteListener {
                Log.d(TAG, "Google sign out complete")
            }
    }

    fun isLoggedInWithFacebook(): Boolean {
        val accessToken = AccessToken.getCurrentAccessToken()
        return accessToken != null && !accessToken.isExpired
    }
}


