package com.example.sociallogin

import android.content.Intent
import android.os.Bundle
import android.widget.Button
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class LoginActivity : AppCompatActivity(), SocialLoginCallback {

    private lateinit var socialLoginManager: SocialLoginManager
    private lateinit var statusText: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        statusText = findViewById(R.id.statusText)

        // Initialize BEFORE calling registerForActivityResult (must be before STARTED state)
        socialLoginManager = SocialLoginManager(this)
        socialLoginManager.initialize(this)

        findViewById<Button>(R.id.btnFacebookLogin).setOnClickListener {
            socialLoginManager.loginWithFacebook()
        }

        findViewById<Button>(R.id.btnGoogleLogin).setOnClickListener {
            socialLoginManager.loginWithGoogle()
        }

        findViewById<Button>(R.id.btnLogout).setOnClickListener {
            socialLoginManager.logout()
            statusText.text = "Logged out"
        }
    }

    @Deprecated("Deprecated in Java")
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        socialLoginManager.handleFacebookActivityResult(requestCode, resultCode, data)
    }

    override fun onLoginSuccess(result: SocialLoginResult) {
        val message = "Logged in via ${result.provider}\n" +
                "User: ${result.displayName ?: result.userId}\n" +
                "Email: ${result.email ?: "N/A"}"
        statusText.text = message
        Toast.makeText(this, "Login successful!", Toast.LENGTH_SHORT).show()

        // IMPORTANT: Send result.token to your backend server for verification
        // Your server holds the secrets and validates the token
        sendTokenToBackend(result)
    }

    override fun onLoginFailure(provider: String, error: String) {
        statusText.text = "Login failed ($provider): $error"
        Toast.makeText(this, "Login failed: $error", Toast.LENGTH_LONG).show()
    }

    override fun onLoginCancelled(provider: String) {
        statusText.text = "Login cancelled ($provider)"
    }

    private fun sendTokenToBackend(result: SocialLoginResult) {
        // TODO: Send the token to your backend server via HTTPS
        // The backend server (which securely stores the App Secret / Client Secret)
        // will verify the token with Facebook/Google servers
        //
        // Example:
        // apiService.verifyToken(VerifyTokenRequest(
        //     provider = result.provider,
        //     token = result.token
        // ))
    }
}


